// ============================
// 02 — Extrair dados + Validar API Key + Idempotência
// ============================

const headers = $input.first().json.headers;
const body = $input.first().json.body;

// Validar x-api-key
const expectedKey = $env.N8N_WEBHOOK_SECRET;
const receivedKey = headers['x-api-key'] || headers['X-Api-Key'];

if (!receivedKey || receivedKey !== expectedKey) {
  throw new Error('Unauthorized: x-api-key inválida ou ausente');
}

const record = body.record;

if (!record || !record.id) {
  throw new Error('Payload inválido: record.id ausente');
}

// Filtrar: só processar fotos de captura pública (captured_by IS NULL)
if (record.captured_by !== null && record.captured_by !== undefined) {
  // Captura manual pelo operador — não processar
  return [];
}

// Filtrar: só processar se status é pending_ai
if (record.processing_status !== 'pending_ai') {
  // Já processado ou em andamento — abort silencioso
  return [];
}

return [{
  json: {
    record_id: record.id,
    guia_id: record.guia_id,
    numero_carteira: record.numero_carteira,
    storage_path: record.storage_path,
    operator_id: record.operator_id,
    sequence: record.sequence,
    created_at: record.created_at
  }
}];

// Converter binário para base64 para enviar ao remove.bg
const binaryData = $input.first().binary;
if (!binaryData || !binaryData.data) {
  throw new Error('Imagem binária não encontrada no input');
}

// Acessar o buffer binário
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Image = buffer.toString('base64');

// Preservar dados do contexto
const context = $('02 — Extrair Dados e Validar').first().json;

return [{
  json: {
    image_base64: base64Image,
    ...context
  }
}];

// Converter cutout PNG para base64
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const cutoutBase64 = buffer.toString('base64');

const context = $('02 — Extrair Dados e Validar').first().json;

return [{
  json: {
    cutout_base64: cutoutBase64,
    ...context
  }
}];

