// Parsear resposta do Claude Vision
const response = $input.first().json;

let qualityData;
try {
  const textContent = response.content.find(c => c.type === 'text');
  if (!textContent) throw new Error('Resposta Claude sem conteúdo text');

  // Limpar possíveis backticks
  const cleanJson = textContent.text.replace(/```json\n?|```\n?/g, '').trim();
  qualityData = JSON.parse(cleanJson);
} catch (e) {
  throw new Error(`Falha ao parsear resposta Claude Vision: ${e.message}`);
}

const context = $('02 — Extrair Dados e Validar').first().json;
const cutoutBase64 = $('05b — Cutout para Base64').first().json.cutout_base64;

return [{
  json: {
    ...qualityData,
    cutout_base64: cutoutBase64,
    ...context
  }
}];

// Polling para aguardar resultado do Replicate
const predictionUrl = $input.first().json.urls.get;
const replicateToken = $env.REPLICATE_API_TOKEN;

let attempts = 0;
const maxAttempts = 30;
const pollInterval = 3000; // 3s

while (attempts < maxAttempts) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: predictionUrl,
    headers: {
      'Authorization': `Bearer ${replicateToken}`
    }
  });

  if (response.status === 'succeeded') {
    const context = $('06b — Parsear Quality Check').first().json;
    return [{
      json: {
        enhanced_url: response.output,
        quality_score: context.quality_score,
        record_id: context.record_id,
        guia_id: context.guia_id,
        numero_carteira: context.numero_carteira,
        operator_id: context.operator_id,
        cutout_base64: context.cutout_base64
      }
    }];
  }

  if (response.status === 'failed' || response.status === 'canceled') {
    // Fallback: usar cutout sem enhancement
    console.log('CodeFormer falhou, usando cutout original como fallback');
    const context = $('06b — Parsear Quality Check').first().json;
    return [{
      json: {
        enhanced_url: null,
        use_cutout_fallback: true,
        quality_score: context.quality_score,
        record_id: context.record_id,
        guia_id: context.guia_id,
        numero_carteira: context.numero_carteira,
        operator_id: context.operator_id,
        cutout_base64: context.cutout_base64
      }
    }];
  }

  attempts++;
  await new Promise(resolve => setTimeout(resolve, pollInterval));
}

// Timeout: usar fallback
console.log('CodeFormer timeout, usando cutout original');
const context = $('06b — Parsear Quality Check').first().json;
return [{
  json: {
    enhanced_url: null,
    use_cutout_fallback: true,
    quality_score: context.quality_score,
    record_id: context.record_id,
    guia_id: context.guia_id,
    numero_carteira: context.numero_carteira,
    operator_id: context.operator_id,
    cutout_base64: context.cutout_base64
  }
}];

// Baixar imagem enhanced do Replicate OU usar cutout como fallback
const input = $input.first().json;
let subjectBase64;

if (input.use_cutout_fallback || !input.enhanced_url) {
  // Fallback: usar cutout original
  subjectBase64 = input.cutout_base64;
} else {
  // Baixar imagem enhanced
  const enhancedUrl = input.enhanced_url;
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: enhancedUrl,
    encoding: 'arraybuffer',
    returnFullResponse: true
  });
  subjectBase64 = Buffer.from(response.body).toString('base64');
}

return [{
  json: {
    subject_base64: subjectBase64,
    record_id: input.record_id,
    guia_id: input.guia_id,
    numero_carteira: input.numero_carteira,
    operator_id: input.operator_id,
    quality_score: input.quality_score
  }
}];

// Preparar array de fundos para o loop
const files = $input.first().json.files;
const context = $('08c — Download Enhanced / Fallback').first().json;

if (!files || files.length === 0) {
  throw new Error('Nenhum fundo encontrado na pasta do Google Drive');
}

return files.map(file => ({
  json: {
    bg_file_id: file.id,
    bg_file_name: file.name,
    bg_mime_type: file.mimeType,
    bg_name_no_ext: file.name.replace(/\.[^/.]+$/, ''),
    subject_base64: context.subject_base64,
    record_id: context.record_id,
    guia_id: context.guia_id,
    numero_carteira: context.numero_carteira,
    operator_id: context.operator_id,
    quality_score: context.quality_score,
    total_backgrounds: files.length
  }
}));

// ============================
// 12 — Composição com Sharp
// ============================
const sharp = require('sharp');

const context = $('10 — Split In Batches').first().json;
const bgBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const subjectBuffer = Buffer.from(context.subject_base64, 'base64');

const OUTPUT_W = Number($env.OUTPUT_WIDTH) || 800;
const OUTPUT_H = Number($env.OUTPUT_HEIGHT) || 1000;
const QUALITY = Number($env.OUTPUT_JPEG_QUALITY) || 90;
const TOP_OFFSET = Number($env.SUBJECT_TOP_OFFSET_PERCENT) || 15;
const SCALE = Number($env.SUBJECT_SCALE_PERCENT) || 85;

// Redimensionar sujeito
const subjectResized = await sharp(subjectBuffer)
  .resize(
    Math.floor(OUTPUT_W * SCALE / 100),
    Math.floor(OUTPUT_H * SCALE / 100),
    { fit: 'inside', withoutEnlargement: false }
  )
  .toBuffer();

const subjectMeta = await sharp(subjectResized).metadata();
const left = Math.floor((OUTPUT_W - subjectMeta.width) / 2);
const top = Math.floor(OUTPUT_H * TOP_OFFSET / 100);

// Compor
const composed = await sharp(bgBuffer)
  .resize(OUTPUT_W, OUTPUT_H, { fit: 'cover' })
  .composite([{
    input: subjectResized,
    left,
    top,
    blend: 'over'
  }])
  .jpeg({ quality: QUALITY })
  .toBuffer();

const composedBase64 = composed.toString('base64');
const bgNameNoExt = context.bg_name_no_ext;
const storagePath = `patients/${context.guia_id}/photos/${context.record_id}/${bgNameNoExt}.jpg`;

return [{
  json: {
    composed_base64: composedBase64,
    storage_path: storagePath,
    bg_name_no_ext: bgNameNoExt,
    record_id: context.record_id,
    guia_id: context.guia_id,
    numero_carteira: context.numero_carteira,
    operator_id: context.operator_id,
    quality_score: context.quality_score,
    total_backgrounds: context.total_backgrounds
  }
}];

// Preparar dados para acumular no loop
const context = $('12 — Composição Sharp').first().json;

const publicUrl = `${$env.SUPABASE_URL}/storage/v1/object/public/patients/${context.storage_path}`;

return [{
  json: {
    photo_record: {
      biometria_foto_id: context.record_id,
      guia_id: context.guia_id,
      numero_carteira: context.numero_carteira,
      operator_id: context.operator_id,
      background_name: context.bg_name_no_ext,
      storage_path: `patients/${context.storage_path}`,
      public_url: publicUrl,
      status: 'ready'
    },
    record_id: context.record_id,
    guia_id: context.guia_id,
    operator_id: context.operator_id,
    quality_score: context.quality_score,
    total_backgrounds: context.total_backgrounds
  }
}];

// Construir array de registros para INSERT batch
const items = $input.first().json.all_photos;
const records = items.map(item => item.photo_record);
const meta = items[0]; // pegar metadata do primeiro item

return [{
  json: {
    records: records,
    record_id: meta.record_id,
    guia_id: meta.guia_id,
    operator_id: meta.operator_id,
    quality_score: meta.quality_score,
    total_photos: records.length
  }
}];
